import React, { useEffect, useMemo, useState } from 'react';
import api from '../axios';
import TaskCard from '../components/TaskCard';

export default function Dashboard() {
  const [items, setItems] = useState([]);
  const [total, setTotal] = useState(0);
  const [loading, setLoading] = useState(true);
  const [query, setQuery] = useState('');
  const [status, setStatus] = useState('all');
  const [priority, setPriority] = useState('all');
  const [page, setPage] = useState(1);
  const [limit, setLimit] = useState(12);
  const [sort, setSort] = useState('createdAt');
  const [order, setOrder] = useState('desc');

  async function loadTasks() {
    setLoading(true);
    const { data } = await api.get('/tasks', {
      params: {
        q: query || undefined,
        status: status !== 'all' ? status : undefined,
        priority: priority !== 'all' ? priority : undefined,
        page,
        limit,
        sort,
        order,
      },
    });
    setItems(data.items);
    setTotal(data.total);
    setLoading(false);
  }

  useEffect(() => { loadTasks(); }, [query, status, priority, page, limit, sort, order]);

  async function toggleStatus(task) {
    const updated = { status: task.status === 'Completed' ? 'Pending' : 'Completed' };
    await api.put(`/tasks/${task._id}`, updated);
    loadTasks();
  }

  async function deleteTask(task) {
    await api.delete(`/tasks/${task._id}`);
    loadTasks();
  }

  const totalPages = Math.max(1, Math.ceil(total / limit));

  if (loading) return <div className="text-gray-600">Loading...</div>;

  return (
    <div className="space-y-4">
      <div className="relative overflow-hidden rounded-2xl border bg-white/70 backdrop-blur p-4">
        <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
          <input
            placeholder="Search tasks..."
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            className="w-full border rounded-lg px-3 py-2 focus:outline-none focus:ring-2 focus:ring-indigo-500"
          />
          <select
            value={status}
            onChange={(e) => setStatus(e.target.value)}
            className="w-full border rounded-lg px-3 py-2 focus:outline-none focus:ring-2 focus:ring-indigo-500"
          >
            <option value="all">All statuses</option>
            <option value="pending">Pending</option>
            <option value="completed">Completed</option>
          </select>
          <select
            value={priority}
            onChange={(e) => setPriority(e.target.value)}
            className="w-full border rounded-lg px-3 py-2 focus:outline-none focus:ring-2 focus:ring-indigo-500"
          >
            <option value="all">All priorities</option>
            <option value="low">Low</option>
            <option value="medium">Medium</option>
            <option value="high">High</option>
          </select>
        </div>
      </div>

      <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3">
        {items.map((t) => (
          <TaskCard key={t._id} task={t} onToggle={toggleStatus} onDelete={deleteTask} />
        ))}
        {items.length === 0 && (
          <div className="text-gray-600">No tasks match your filters.</div>
        )}
      </div>

      <div className="flex items-center justify-between gap-3 pt-2">
        <div className="text-sm text-gray-600">Page {page} of {totalPages} • {total} items</div>
        <div className="flex items-center gap-2">
          <button
            className="px-3 py-1.5 rounded-md border disabled:opacity-50"
            onClick={() => setPage((p) => Math.max(1, p - 1))}
            disabled={page <= 1}
          >
            Previous
          </button>
          <button
            className="px-3 py-1.5 rounded-md border disabled:opacity-50"
            onClick={() => setPage((p) => Math.min(totalPages, p + 1))}
            disabled={page >= totalPages}
          >
            Next
          </button>
          <select
            value={sort}
            onChange={(e) => setSort(e.target.value)}
            className="ml-2 border rounded px-2 py-1"
          >
            <option value="createdAt">Created</option>
            <option value="dueDate">Due date</option>
            <option value="priority">Priority</option>
          </select>
          <select
            value={order}
            onChange={(e) => setOrder(e.target.value)}
            className="border rounded px-2 py-1"
          >
            <option value="desc">Desc</option>
            <option value="asc">Asc</option>
          </select>
        </div>
      </div>
    </div>
  );
}
